/**
 * @component DestructiveModal
 * @description A modal popup to confirm an action, typically deletion.
 * Its content (title, message, button text) and the confirm action
 * are configured when it's opened via the `ElementStore`.
 * The modal's visibility is controlled by the `isOpen` prop, which should
 * reflect the corresponding state in the `ElementStore` (e.g., `elementStore.openState.destructiveModal`).
 * 
 * @type {{
 *   isOpen?: boolean; // Controls the visibility of the modal. This should be reactively bound to the store state by the parent component.
 * }}
 * 
 * @example
 * // To open the modal from JavaScript (e.g., in another component or store):
 * // import { AppStore } from '$lib/stores/AppStore.svelte';
 * // const elementStore = AppStore.elements;
 * //
 * // elementStore.open('destructiveModal', {
 * //   title: 'Delete Download?',
 * //   content: 'Are you sure you want to delete this downloaded episode? This action cannot be undone.',
 * //   confirmText: 'Delete',
 * //   cancelText: 'Cancel',
 * //   onConfirm: () => {
 * //     console.log('Delete action confirmed');
 * //     // Perform actual deletion logic here
 * //   }
 * // });
 * 
 * // In a Svelte layout/page component that renders global modals:
 * // <script>
 * //   import { AppStore } from '$lib/stores/AppStore.svelte.js';
 * //   import DestructiveModal from '$lib/components/common/modal/DestructiveModal.svelte';
 * //
 * //   let isModalOpen = $derived(AppStore.elements.openState.destructiveModal || false);
 * // <\/script>
 * //
 * // {#if isModalOpen}
 * //   <DestructiveModal bind:isOpen={isModalOpen} />
 * // {/if}
 * // Note: The modal internally handles closing itself by updating the elementStore.
 */

/**
 * @component PopupLogin
 * @description A component that provides a login and registration flow within a side drawer.
 *              It uses an AnimatedStepper to manage the sequence of steps, such as email entry,
 *              password creation, and password reset. It is controlled via the PopupLoginStore
 *              and ElementStore.
 * 
 * @example
 * // This component is typically rendered once in a root layout file and controlled globally.
 * // To open the popup from any other component or page:
 * 
 * ```svelte
 * 
 *   import { appStore } from '$lib/stores/AppStore.svelte.js';
 *   import Button from '$lib/components/common/input/Button.svelte';
 * 
 *   // 1. Basic login/registration flow
 *   function openLogin() {
 *     appStore.popupLogin.open({
 *       onComplete: (result) => {
 *         console.log('Flow complete!', result);
 *         // result object contains details about how the flow ended,
 *         // e.g., { registrationSuccess: true, lastStepComponent: 'registerName' }
 *       }
 *     });
 *   }
 * 
 *   // 2. Login flow that proceeds to payment on completion
 *   function openLoginWithPayment() {
 *     appStore.popupLogin.open({
 *       requiresPayment: true,
 *       onComplete: (result) => {
 *         if (result?.subscriptionSuccess) {
 *           console.log('Subscription successful!');
 *         }
 *       }
 *     });
 *   }
 * 
 *   // 3. Open directly to a specific step (e.g., for a logged-in user to subscribe)
 *   function openPaymentForLoggedInUser() {
 *     appStore.popupLogin.open({
 *       initialStepName: 'subscriptionPlan',
 *       requiresPayment: true,
 *       onComplete: (result) => console.log('Flow complete!', result)
 *     });
 *   }
 * 
 * 
 * <Button on:click={openLogin}>Log In</Button>
 * <Button on:click={openLoginWithPayment}>Subscribe</Button>
 * ```
 */

